import{_ as t,a,b as r,c as d,d as n,e as o}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as i,o as s,c as l,a2 as p}from"./chunks/framework.DnrXFDHb.js";const D=JSON.parse('{"title":"Dropbox-Kanal hinzufügen","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/upload/dropbox.md","filePath":"de-DE/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"de-DE/upload/dropbox.md"};function h(u,e,b,g,f,m){return s(),l("div",null,[...e[0]||(e[0]=[p('<h1 id="dropbox-kanal-hinzufugen" tabindex="-1">Dropbox-Kanal hinzufügen <a class="header-anchor" href="#dropbox-kanal-hinzufugen" aria-label="Permalink to &quot;Dropbox-Kanal hinzufügen&quot;">​</a></h1><h2 id="was-du-vorher-brauchst" tabindex="-1">Was du vorher brauchst <a class="header-anchor" href="#was-du-vorher-brauchst" aria-label="Permalink to &quot;Was du vorher brauchst&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Voraussetzung</th><th>Wofür sie gebraucht wird</th></tr></thead><tbody><tr><td>Dropbox-Konto</td><td>Zum Anmelden und Autorisieren der App</td></tr><tr><td>Dropbox-App</td><td>Erstellt <code>App Key</code> und <code>App Secret</code></td></tr><tr><td>Deine ImgBed-Domain</td><td>Für die OAuth-Redirect-URI</td></tr><tr><td>Freier Dropbox-Speicher</td><td>Dient als eigentlicher Speicherort</td></tr></tbody></table><h2 id="einrichtung" tabindex="-1">Einrichtung <a class="header-anchor" href="#einrichtung" aria-label="Permalink to &quot;Einrichtung&quot;">​</a></h2><h3 id="schritt-1-dropbox-app-erstellen" tabindex="-1">Schritt 1: Dropbox-App erstellen <a class="header-anchor" href="#schritt-1-dropbox-app-erstellen" aria-label="Permalink to &quot;Schritt 1: Dropbox-App erstellen&quot;">​</a></h3><ol><li>Öffne die Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>Erstelle eine neue App.</li><li>Wähle als Zugriffstyp:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>Gib der App einen Namen, den du wiedererkennst, z. B. <code>imgbed-app</code>.</li><li>Öffne nach dem Erstellen die Detailseite der App.</li></ol><p>Empfohlener Zugriffstyp:</p><table tabindex="0"><thead><tr><th>Zugriffstyp</th><th>Empfehlung</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Empfohlen. Das passt dazu, wie ImgBed Dateien ablegt.</td></tr><tr><td><code>Full Dropbox</code></td><td>Nicht empfohlen. ImgBed braucht keinen Vollzugriff auf das ganze Konto.</td></tr></tbody></table><p><img src="'+t+'" alt="Dropbox-App erstellen" loading="lazy"></p><h3 id="schritt-2-redirect-uri-eintragen" tabindex="-1">Schritt 2: Redirect URI eintragen <a class="header-anchor" href="#schritt-2-redirect-uri-eintragen" aria-label="Permalink to &quot;Schritt 2: Redirect URI eintragen&quot;">​</a></h3><p>Suche auf der Detailseite der Dropbox-App die OAuth- oder Redirect-URI-Einstellungen und füge hinzu:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>Wenn du den Adminbereich über mehrere Domains nutzt, trage jede passende Callback-URL ein.</p><p><img src="'+a+'" alt="Redirect URI konfigurieren" loading="lazy"></p><h3 id="schritt-3-app-berechtigungen-konfigurieren" tabindex="-1">Schritt 3: App-Berechtigungen konfigurieren <a class="header-anchor" href="#schritt-3-app-berechtigungen-konfigurieren" aria-label="Permalink to &quot;Schritt 3: App-Berechtigungen konfigurieren&quot;">​</a></h3><p>Öffne den Tab <code>Permissions</code> und aktiviere mindestens diese Scopes:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Erforderlich</th><th>Zweck</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Erforderlich</td><td>Liest Konto- und Quoteninformationen</td></tr><tr><td><code>files.metadata.read</code></td><td>Erforderlich</td><td>Liest Datei- und Ordnermetadaten für Pfadprüfungen</td></tr><tr><td><code>files.metadata.write</code></td><td>Erforderlich</td><td>Erstellt Ordner und schreibt Metadaten</td></tr><tr><td><code>files.content.write</code></td><td>Erforderlich</td><td>Lädt Dateien hoch. Ohne diesen Scope erscheint <code>required scope &#39;files.content.write&#39;</code>.</td></tr><tr><td><code>files.content.read</code></td><td>Empfohlen</td><td>Erlaubt Download, Vorschau und temporäre Dateilinks</td></tr></tbody></table><p>Klicke nach dem Auswählen unten auf <code>Submit</code>.</p><p><img src="'+r+'" alt="Berechtigungen hinzufügen" loading="lazy"></p><p>Wichtig:</p><table tabindex="0"><thead><tr><th>Situation</th><th>Was zu tun ist</th></tr></thead><tbody><tr><td>Du hast Scopes geändert</td><td>Starte die Token-Autorisierung erneut und hole ein neues <code>Refresh Token</code>.</td></tr><tr><td>Du hast nicht erneut autorisiert</td><td>Das alte Token bekommt die neuen Rechte nicht automatisch; Uploads können weiter fehlschlagen.</td></tr></tbody></table><h3 id="schritt-4-app-zugangsdaten-kopieren" tabindex="-1">Schritt 4: App-Zugangsdaten kopieren <a class="header-anchor" href="#schritt-4-app-zugangsdaten-kopieren" aria-label="Permalink to &quot;Schritt 4: App-Zugangsdaten kopieren&quot;">​</a></h3><p>Speichere diese beiden Werte von der Dropbox-App-Seite:</p><table tabindex="0"><thead><tr><th>Dropbox-Feld</th><th>ImgBed-Feld</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="schritt-5-dropbox-kanal-ausfullen" tabindex="-1">Schritt 5: Dropbox-Kanal ausfüllen <a class="header-anchor" href="#schritt-5-dropbox-kanal-ausfullen" aria-label="Permalink to &quot;Schritt 5: Dropbox-Kanal ausfüllen&quot;">​</a></h3><p>Wähle in den Upload-Einstellungen <code>Dropbox</code> und fülle aus:</p><table tabindex="0"><thead><tr><th>ImgBed-Feld</th><th>Eingabe</th></tr></thead><tbody><tr><td>Kanalname</td><td>Ein gut erkennbarer Name, z. B. <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Der Dropbox-<code>App key</code></td></tr><tr><td>App Secret</td><td>Das Dropbox-<code>App secret</code></td></tr><tr><td>Refresh Token</td><td>Erst einmal leer lassen</td></tr><tr><td>Stammverzeichnis</td><td>Optional. Standard ist <code>imgbed</code>.</td></tr><tr><td>Notiz</td><td>Optional</td></tr></tbody></table><p><img src="'+d+'" alt="Token abrufen" loading="lazy"></p><h3 id="schritt-6-refresh-token-abrufen" tabindex="-1">Schritt 6: Refresh Token abrufen <a class="header-anchor" href="#schritt-6-refresh-token-abrufen" aria-label="Permalink to &quot;Schritt 6: Refresh Token abrufen&quot;">​</a></h3><ol><li>Klicke in ImgBed auf <code>Get Token</code>.</li><li>Melde dich mit dem Dropbox-Konto an, das du verbinden möchtest.</li><li>Bestätige die Autorisierung.</li><li>Die Callback-Seite zeigt ein <code>Refresh Token</code>.</li><li>Kopiere es.</li><li>Kehre zu ImgBed zurück und füge es in das Feld <code>Refresh Token</code> ein.</li></ol><p><img src="'+n+'" alt="Token kopieren" loading="lazy"></p><h2 id="prufung" tabindex="-1">Prüfung <a class="header-anchor" href="#prufung" aria-label="Permalink to &quot;Prüfung&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Prüfung</th><th>Erwartetes Ergebnis</th></tr></thead><tbody><tr><td>Kanalkarte</td><td>Der Dropbox-Kanal erscheint nach dem Speichern.</td></tr><tr><td>Kanalschalter</td><td>Der Kanal lässt sich aktivieren.</td></tr><tr><td>Token gespeichert</td><td>Die Detailseite zeigt, dass das <code>Refresh Token</code> gespeichert wurde.</td></tr><tr><td>Testupload</td><td>Ein Testbild erscheint im App-Ordner von Dropbox.</td></tr></tbody></table><p>Wenn Quotenlimits aktiviert sind, klicke auf die Quotenabfrage. Nach erfolgreicher Abfrage zeigt die Kanalkarte belegten Speicher, Gesamtspeicher und die letzte Aktualisierung an.</p><p><img src="'+o+`" alt="Quotenabfrage erfolgreich" loading="lazy"></p><h2 id="fehlersuche" tabindex="-1">Fehlersuche <a class="header-anchor" href="#fehlersuche" aria-label="Permalink to &quot;Fehlersuche&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Lösung</th></tr></thead><tbody><tr><td>ImgBed meldet, dass die Konfiguration unvollständig ist</td><td>Prüfe, ob <code>App Key</code>, <code>App Secret</code> und <code>Refresh Token</code> alle ausgefüllt sind.</td></tr><tr><td>Autorisierung klappt, aber es erscheint kein <code>Refresh Token</code></td><td>Klicke erneut auf <code>Get Token</code> und achte darauf, dass der Offline-Autorisierungsablauf verwendet wird.</td></tr><tr><td>Upload schlägt mit <code>required scope &#39;files.content.write&#39;</code> fehl</td><td>Aktiviere <code>files.content.write</code>, klicke auf <code>Submit</code> und hole danach ein neues <code>Refresh Token</code>.</td></tr><tr><td>Callback schlägt fehl</td><td>Prüfe, ob die Redirect URI <code>https://your-domain.com/api/oauth/dropbox/callback</code> lautet.</td></tr><tr><td>Dateien werden nicht gefunden</td><td>Prüfe, ob die Dropbox-App im Modus <code>App folder</code> erstellt wurde.</td></tr></tbody></table><h2 id="kurzablauf" tabindex="-1">Kurzablauf <a class="header-anchor" href="#kurzablauf" aria-label="Permalink to &quot;Kurzablauf&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dropbox App Console öffnen</span></span>
<span class="line"><span>-&gt; App erstellen</span></span>
<span class="line"><span>-&gt; Zugriffstyp App folder wählen</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/dropbox/callback eintragen</span></span>
<span class="line"><span>-&gt; account_info.read / files.metadata.read / files.metadata.write / files.content.write aktivieren</span></span>
<span class="line"><span>-&gt; Optional files.content.read aktivieren</span></span>
<span class="line"><span>-&gt; Submit klicken</span></span>
<span class="line"><span>-&gt; App Key und App Secret kopieren</span></span>
<span class="line"><span>-&gt; In ImgBed eintragen</span></span>
<span class="line"><span>-&gt; Get Token klicken</span></span>
<span class="line"><span>-&gt; Refresh Token von der Callback-Seite kopieren</span></span>
<span class="line"><span>-&gt; In ImgBed einfügen und speichern</span></span></code></pre></div><h2 id="referenzen" tabindex="-1">Referenzen <a class="header-anchor" href="#referenzen" aria-label="Permalink to &quot;Referenzen&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const A=i(c,[["render",h]]);export{D as __pageData,A as default};
